{"content": "#!/bin/bash
# Batch part 2: Add test scripts and install vitest for remaining sites

SITES=(
  "estudio-contable-paraguay:./"
  "3md-website:./"
  "villamayor-asociados:./"
  "ozmontania-website:./"
  "de-abasto-a-casa:./src"
  "nudo:./src"
  "granja-cabral:./src"
  "stroopwafel-huis:./src"
  "golden-visa-advisory:./src"
  "bufete-mendez:./src"
)

for entry in "${SITES[@]}"; do
  IFS=':' read -r dir alias <<< "$entry"
  base="/root/$dir"

  echo "=== $dir ==="

  # vitest.config.ts
  cat > "$base/vitest.config.ts" << VITEST
import { defineConfig } from "vitest/config"
import react from "@vitejs/plugin-react"
import path from "path"

export default defineConfig({
  plugins: [react()],
  test: {
    environment: "jsdom",
    setupFiles: [],
  },
  resolve: {
    alias: {
      "@": path.resolve(__dirname, "$alias"),
    },
  },
})
VITEST
  echo "  vitest.config.ts ✓"

  # __tests__/basic.test.ts
  mkdir -p "$base/__tests__"
  cat > "$base/__tests__/basic.test.ts" << 'TEST'
import { describe, it, expect } from "vitest"

describe("Site", () => {
  it("has proper test setup", () => {
    expect(1 + 1).toBe(2)
  })

  it("test framework works with jsdom", () => {
    expect(typeof window).toBe("object")
    expect(typeof document).toBe("object")
  })
})
TEST
  echo "  __tests__/basic.test.ts ✓"

  # .github/workflows/ci.yml
  cat > "$base/.github/workflows/ci.yml" << 'CI'
name: CI
on:
  pull_request:
    branches: [main]
  push:
    branches: [main]
jobs:
  ci:
    uses: Ai-Whisperers/ci-cd/.github/workflows/ci-nextjs.yml@main
    with:
      package-manager: 'npm'
      node-version: '20'
    secrets: inherit
CI
  echo "  .github/workflows/ci.yml ✓"

  # Add test script to package.json
  node -e "
const fs = require('fs');
const p = JSON.parse(fs.readFileSync('$base/package.json', 'utf8'));
p.scripts = p.scripts || {};
if (!p.scripts.test) {
  p.scripts.test = 'vitest run';
  fs.writeFileSync('$base/package.json', JSON.stringify(p, null, 2) + '\n');
  console.log('  test script added ✓');
} else {
  console.log('  test script exists: ' + p.scripts.test);
}
" 2>/dev/null

  echo ""
done

echo "=== ALL DONE ==="
", "path": "/root/scripts/batch-add-ci-vitest-2.sh"}

